import {merge} from 'lodash/lodash.min';
import DOFBaseLayer from '../bases/DOFBaseLayer';
import Conversion from '../utils/Conversion';

// Eye/Overlays
let centerX = 0;
let centerY = 0;
let eyeRadiusX = 300;
let eyeRadiusY = 300;

let values = [
    {
        display: 'linear',
        label: 'Linear Tween',
        value: 'linear'
    },
    {
        display: 'sine in',
        label: 'Sine Ease In',
        value: 'sineIn'
    },
    {
        display: 'sine out',
        label: 'Sine Ease Out',
        value: 'sineOut'
    },
    {
        display: 'sine in out',
        label: 'Sine Ease In Out',
        value: 'sineInOut'
    },
    {
        display: 'cubic in',
        label: 'Cubic Ease In',
        value: 'cubicIn'
    },
    {
        display: 'cubic out',
        label: 'Cubic Ease Out',
        value: 'cubicOut'
    },
    {
        display: 'cubic in out',
        label: 'Cubic Ease In Out',
        value: 'cubicInOut'
    }
];

let Tween = {
    type: {
        name: 'enum',
        values
    },
    defaultValue: values[3],
    blendOperation: 'none'
};

let VertexType = (xRelativeToCenter, yRelativeToCenter) => {
    return {
        type: "vector2",
        defaultValue: {
            x: xRelativeToCenter,
            y: yRelativeToCenter
        },
        blendOperation: "add"
    };
};

let Info = {
    properties: {
        Rotate: {
            type: "float",
            defaultValue: 0.0,
            blendOperation: "add"
        },
        Scale: {
            type: "vector2",
            defaultValue: {
                x: 1,
                y: 1
            },
            blendOperation: "multiply"
        },
        Translate: {
            type: "vector2",
            defaultValue: {
                x: centerX,
                y: centerY
            },
            blendOperation: "add"
        },
        Visible: {
            type: "bool",
            defaultValue: true,
            blendOperation: "lastOneWins"
        },
        Alpha: {
            type: "float",
            defaultValue: 1.0,
            blendOperation: "multiply"
        },
        Tween,
        "Vertex 1": VertexType(-eyeRadiusX, -eyeRadiusY),
        "Vertex 2": VertexType(0, -eyeRadiusY),
        "Vertex 3": VertexType(eyeRadiusX, -eyeRadiusY),
        "Vertex 4": VertexType(-eyeRadiusX, 0),
        "Vertex 5": VertexType(0, 0),
        "Vertex 6": VertexType(eyeRadiusX, 0),
        "Vertex 7": VertexType(-eyeRadiusX, eyeRadiusY),
        "Vertex 8": VertexType(0, eyeRadiusY),
        "Vertex 9": VertexType(eyeRadiusX, eyeRadiusY)
    }
};

export default class EyeAndOverlayLayer extends DOFBaseLayer {

    static get eyeRadiusY() {
        return eyeRadiusY;
    }

    static get eyeRadiusX() {
        return eyeRadiusX;
    }

    static _generateDofs(props, nameStem) {
        return {
            [nameStem + "vertexJoint1_t"]: Conversion.toMetersX(props['Vertex 1'].x) * props.Scale.x,
            [nameStem + "vertexJoint1_t_2"]: Conversion.toMetersY(props['Vertex 1'].y) * props.Scale.y,
            [nameStem + "vertexJoint2_t"]: Conversion.toMetersX(props['Vertex 2'].x) * props.Scale.x,
            [nameStem + "vertexJoint2_t_2"]: Conversion.toMetersY(props['Vertex 2'].y) * props.Scale.y,
            [nameStem + "vertexJoint3_t"]: Conversion.toMetersX(props['Vertex 3'].x) * props.Scale.x,
            [nameStem + "vertexJoint3_t_2"]: Conversion.toMetersY(props['Vertex 3'].y) * props.Scale.y,
            //
            [nameStem + "vertexJoint4_t"]: Conversion.toMetersX(props['Vertex 4'].x) * props.Scale.x,
            [nameStem + "vertexJoint4_t_2"]: Conversion.toMetersY(props['Vertex 4'].y) * props.Scale.y,
            [nameStem + "vertexJoint5_t"]: Conversion.toMetersX(props['Vertex 5'].x) * props.Scale.x,
            [nameStem + "vertexJoint5_t_2"]: Conversion.toMetersY(props['Vertex 5'].y) * props.Scale.y,
            [nameStem + "vertexJoint6_t"]: Conversion.toMetersX(props['Vertex 6'].x) * props.Scale.x,
            [nameStem + "vertexJoint6_t_2"]: Conversion.toMetersY(props['Vertex 6'].y) * props.Scale.y,
            //
            [nameStem + "vertexJoint7_t"]: Conversion.toMetersX(props['Vertex 7'].x) * props.Scale.x,
            [nameStem + "vertexJoint7_t_2"]: Conversion.toMetersY(props['Vertex 7'].y) * props.Scale.y,
            [nameStem + "vertexJoint8_t"]: Conversion.toMetersX(props['Vertex 8'].x) * props.Scale.x,
            [nameStem + "vertexJoint8_t_2"]: Conversion.toMetersY(props['Vertex 8'].y) * props.Scale.y,
            [nameStem + "vertexJoint9_t"]: Conversion.toMetersX(props['Vertex 9'].x) * props.Scale.x,
            [nameStem + "vertexJoint9_t_2"]: Conversion.toMetersY(props['Vertex 9'].y) * props.Scale.y
        };
    }

    static overrideProperties(newProps) {
        Object.assign(Info.properties, newProps);
    }

    static extend(input) {
        let result = merge({}, Info, input);
        return result;
    }
}
